import React, {useState} from "react";

function VideoCard({videoUrl, title, h, w}) {

  const [modal, setModal] = useState(false);
  const [videoLoading, setVideoLoading] = useState(true);

  function openModal(){
    setModal(!modal);
  };

  return (

    
  <div className="">
    <button onClick={openModal}>Abrir Modal</button>

      {modal ? (
          <section className="">
            <div className="">
              <div className="" modal={modal}>
                <button
                  className=""
                  onClick={setModal}
                >X</button>
                <div className="">
                  {
                    <iframe 
                        width={w} 
                        height={h}
                        src={videoUrl} 
                        title={title}
                        frameborder="0" 
                        allow="accelerometer; 
                        autoplay; 
                        clipboard-write; 
                        encrypted-media; 
                        gyroscope; 
                        picture-in-picture; 
                        web-share" 
                        referrerpolicy="strict-origin-when-cross-origin" 
                        allowfullscreen>
                    </iframe>
                  }
                </div>
              </div>
            </div>
          </section>
        ) : null}
    </div>
  );
}

export default VideoCard;
